async function fetchWeatherData(city, apiKey) {
  try {
    const response = await fetch(`https://api.openweathermap.org/data/2.5/forecast?q=${city}&appid=${apiKey}&units=metric&lang=de`);
    if (!response.ok) {
      throw new Error(`Failed to fetch weather data for ${city}`);
    }
    const data = await response.json();
    return data;
  } catch (error) {
    console.error('Error fetching weather data:', error);
    return null;
  }
}

// Function to create a five-day forecast
function createForecast(data) {
  const forecast = [];
  const today = new Date();
  const todayDay = today.getDay();
  const todayDate = today.getDate();
  const todayMonth = today.getMonth();
  const todayYear = today.getFullYear();

  for (let i = 0; i < 5; i++) {
    const date = new Date(todayYear, todayMonth, todayDate + i);
    const day = date.getDay();
    const dateStr = date.toLocaleDateString();
    const high = data.list[i].main.temp;
    const low = data.list[i].main.temp_min;
    const chanceOfPrecip = data.list[i].popcnt > 0 ? data.list[i].popcnt + '% chance of precipitation' : 'No precipitation';

    forecast.push({
      date: dateStr,
      day: day,
      high: high,
      low: low,
      chanceOfPrecip: chanceOfPrecip
    });
  }

  return forecast;
}

